Функция ПолучитьСуммарныйДолгПоКонтрагенту(СсылкаНаКонтрагента) Экспорт
    Запрос = Новый Запрос;
    Запрос.Текст = "ВЫБРАТЬ |   Взаиморасчеты.Ссылка КАК Ссылка, |   Взаиморасчеты.Остаток КАК Остаток |ИЗ | РегистрНакопления.Взаиморасчеты КАК Взаиморасчеты |ГДЕ |  Взаиморасчеты.Период МЕЖДУ &НачПериод И &КонецПериода | И | Взаиморасчеты.Измерение1 = &Контрагент";
    Запрос.УстановитьПараметр("НачПериод", Дата(1900, 1, 1));
    Запрос.УстановитьПараметр("КонецПериода", ТекущаяДата());
    Запрос.УстановитьПараметр("Контрагент", СсылкаНаКонтрагента);

    РезультатЗапроса = Запрос.Выполнить();
    ВыборкаДетальныхЗаписей = РезультатЗапроса.Выбрать();

    СуммаДолга = 0;
    Пока ВыборкаДетальныхЗаписей.Следующий() Цикл
        Если ВыборкаДетельныхЗаписей.Остаток > 0 Тогда
            СуммаДолга += ВыборкаДетальныхЗаписей.Остаток;
        КонецЕсли;
    КонецЦикла;

    Возврат СуммаДолга;
КонецФункции
